import React, { useState } from 'react';
import './BookingScreen.css';

const TIME_SLOTS = [
  '09:00', '09:30', '10:00', '10:30',
  '11:00', '11:30', '13:00', '13:30',
  '14:00', '14:30', '15:00', '15:30',
];

const FARE = 2500;

export default function BookingScreen({ departure, destination, onBack, onConfirm }) {
  const [selectedTime, setSelectedTime] = useState(null);
  const [passengers, setPassengers] = useState(1);

  const total = FARE * passengers;

  const handleConfirm = () => {
    if (!selectedTime) return;
    onConfirm({
      departure,
      destination,
      time: selectedTime,
      passengers,
      total,
    });
  };

  return (
    <div className="booking-screen">
      {/* 헤더 */}
      <div className="booking-header">
        <button className="back-btn" onClick={onBack}>
          <span>‹</span>
        </button>
        <h2 className="booking-title">예약하기</h2>
        <div style={{ width: 40 }} />
      </div>

      {/* 여정 요약 카드 */}
      <div className="journey-card">
        <div className="journey-emoji">{destination.emoji}</div>
        <div className="journey-detail">
          <p className="journey-dest">{destination.name}</p>
          <p className="journey-from">
            {departure} 출발 · {destination.distance} · {destination.duration}
          </p>
        </div>
      </div>

      {/* 시간 선택 */}
      <section className="booking-section">
        <p className="booking-label">탑승 시간 선택</p>
        <div className="time-grid">
          {TIME_SLOTS.map((t) => (
            <button
              key={t}
              className={`time-btn ${selectedTime === t ? 'active' : ''}`}
              onClick={() => setSelectedTime(t)}
            >
              {t}
            </button>
          ))}
        </div>
      </section>

      {/* 인원 선택 */}
      <section className="booking-section">
        <p className="booking-label">탑승 인원</p>
        <div className="passenger-row">
          <div className="passenger-ctrl">
            <button
              className="pax-btn"
              onClick={() => setPassengers((p) => Math.max(1, p - 1))}
              disabled={passengers <= 1}
            >
              −
            </button>
            <span className="pax-count">{passengers}명</span>
            <button
              className="pax-btn"
              onClick={() => setPassengers((p) => Math.min(8, p + 1))}
              disabled={passengers >= 8}
            >
              +
            </button>
          </div>
          <p className="pax-note">최대 8명</p>
        </div>
      </section>

      {/* 요금 카드 */}
      <div className="fare-card">
        <div className="fare-row">
          <span className="fare-label">기본 요금</span>
          <span className="fare-val">2,500원 × {passengers}명</span>
        </div>
        <div className="fare-divider" />
        <div className="fare-row total">
          <span>총 요금</span>
          <span className="fare-total">{total.toLocaleString()}원</span>
        </div>
      </div>

      {/* 예약 확정 버튼 */}
      <div className="confirm-wrap">
        <button
          className={`confirm-btn ${!selectedTime ? 'disabled' : ''}`}
          onClick={handleConfirm}
          disabled={!selectedTime}
        >
          {selectedTime ? `${selectedTime} 예약 확정` : '시간을 선택하세요'}
        </button>
      </div>
    </div>
  );
}
